import { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import { logoutUser } from "../services/auth";
import { getPolicies } from "../services/firestore";
import { useAuth } from "../context/AuthContext";
import ActionSelector from "../components/ActionSelector";

export default function AgentDashboard() {
  const [searchQuery, setSearchQuery] = useState("");
  const [policies, setPolicies] = useState([]);
  const [loading, setLoading] = useState(true);
  const navigate = useNavigate();
  const { userProfile } = useAuth();

  useEffect(() => {
    const fetchLivePolicies = async () => {
      const data = await getPolicies();
      setPolicies(data);
      setLoading(false);
    };
    fetchLivePolicies();
  }, []);

  const handleLogout = async () => {
    await logoutUser();
    navigate("/login");
  };

  const filteredPolicies = policies.filter((policy) => {
    const q = searchQuery.toLowerCase();
    const titleMatch = policy.title?.toLowerCase().includes(q);
    const contentMatch = policy.content?.toLowerCase().includes(q);
    const categoryMatch = policy.category?.toLowerCase().includes(q);
    return titleMatch || contentMatch || categoryMatch;
  });

  const greeting = userProfile?.name || "Agent";

  return (
    <div className="page-bg">
      <nav className="bg-white border-b border-brand-border px-8 py-4 flex justify-between items-center">
        <div>
          <h1 className="text-xl font-extrabold text-brand-navy">Aamer CSR Portal</h1>
          <p className="text-sm text-brand-slate">Welcome, {greeting}</p>
        </div>
        <button
          onClick={handleLogout}
          className="text-brand-slate hover:text-red-600 font-bold text-sm transition-colors"
        >
          Sign Out
        </button>
      </nav>

      <div className="max-w-4xl mx-auto p-8">
        <header className="mb-8">
          <h2 className="page-title">Knowledge Base</h2>
          <p className="page-subtitle">Search policies and log actions during your call.</p>
        </header>

        <ActionSelector />

        <div className="mb-8">
          <input
            type="text"
            placeholder="Search policies by title, content, or category..."
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            className="input-field text-base"
          />
        </div>

        {loading ? (
          <p className="text-brand-slate text-center py-8">Loading policies...</p>
        ) : filteredPolicies.length === 0 ? (
          <div className="card p-8 text-center">
            <p className="text-brand-slate">
              {searchQuery ? "No policies found matching your search." : "No policies in the knowledge base yet."}
            </p>
          </div>
        ) : (
          <div className="space-y-4">
            {filteredPolicies.map((policy) => (
              <article key={policy.id} className="card p-6">
                <div className="flex items-start justify-between gap-4 mb-2">
                  <h3 className="text-xl font-extrabold text-brand-navy">
                    {policy.title || "Untitled Policy"}
                  </h3>
                  {policy.category && (
                    <span className="shrink-0 text-xs font-bold text-brand-slate bg-brand-bg px-2.5 py-1 rounded-full">
                      {policy.category}
                    </span>
                  )}
                </div>
                <p className="text-brand-slate leading-relaxed">{policy.content || "No content available."}</p>
              </article>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}
